import React, { useEffect, useState } from 'react';
import { db } from '../firebase';
import { collection, getDocs, addDoc, deleteDoc, doc, updateDoc, Timestamp } from 'firebase/firestore';
import { useNavigate } from 'react-router-dom';

function PlayersManagement() {
  const [players, setPlayers] = useState([]);
  const [newPlayer, setNewPlayer] = useState({
    firstName: '',
    lastName: '',
    nationality: '',
    favoritePosition: '',
    powerRating: '',
  });
  const navigate = useNavigate();

  useEffect(() => {
    const fetchPlayers = async () => {
      try {
        const playersCollection = await getDocs(collection(db, 'players'));
        const playersData = playersCollection.docs.map(doc => ({
          id: doc.id,
          ...doc.data(),
        }));
        setPlayers(playersData);
      } catch (error) {
        console.error('Error fetching players:', error);
      }
    };

    fetchPlayers();
  }, []);

  const handleChange = (e) => {
    setNewPlayer({ ...newPlayer, [e.target.name]: e.target.value });
  };

  const handleAddPlayer = async (e) => {
    e.preventDefault();
    try {
      await addDoc(collection(db, 'players'), {
        ...newPlayer,
        createdAt: Timestamp.now(),
      });
      alert('Player added successfully!');
      setNewPlayer({
        firstName: '',
        lastName: '',
        nationality: '',
        favoritePosition: '',
        powerRating: '',
      });
      window.location.reload();
    } catch (error) {
      console.error('Error adding player:', error);
    }
  };

  const handleEditPlayer = (playerId) => {
    navigate(`/edit-player/${playerId}`);
  };

  const handleDeletePlayer = async (playerId) => {
    if (window.confirm('Are you sure you want to delete this player?')) {
      await deleteDoc(doc(db, 'players', playerId));
      alert('Player deleted successfully!');
      setPlayers(players.filter(p => p.id !== playerId));
    }
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.title}>Players Management</h1>

      <form onSubmit={handleAddPlayer} style={styles.form}>
        <input
          type="text"
          name="firstName"
          placeholder="First Name"
          value={newPlayer.firstName}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <input
          type="text"
          name="lastName"
          placeholder="Last Name"
          value={newPlayer.lastName}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <input
          type="text"
          name="nationality"
          placeholder="Nationality"
          value={newPlayer.nationality}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <input
          type="text"
          name="favoritePosition"
          placeholder="Favorite Position"
          value={newPlayer.favoritePosition}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <input
          type="number"
          name="powerRating"
          placeholder="Power Rating"
          value={newPlayer.powerRating}
          onChange={handleChange}
          required
          style={styles.input}
        />
        <button type="submit" style={styles.button}>Add Player</button>
      </form>

      <h2 style={styles.subTitle}>All Players</h2>
      <div style={styles.playerList}>
        {players.length > 0 ? (
          players.map(player => (
            <div key={player.id} style={styles.playerCard}>
              <p><strong>Name:</strong> {player.firstName} {player.lastName}</p>
              <p><strong>Nationality:</strong> {player.nationality}</p>
              <p><strong>Position:</strong> {player.favoritePosition}</p>
              <p><strong>Power Rating:</strong> {player.powerRating}</p>

              <div style={styles.buttonGroup}>
                <button style={styles.editButton} onClick={() => handleEditPlayer(player.id)}>Edit</button>
                <button style={styles.removeButton} onClick={() => handleDeletePlayer(player.id)}>Remove</button>
              </div>
            </div>
          ))
        ) : (
          <p>No players found.</p>
        )}
      </div>

      <button style={styles.backButton} onClick={() => navigate('/')}>Back to Main Menu</button>
    </div>
  );
}

const styles = {
  container: {
    backgroundColor: '#D6F8D6',
    minHeight: '100vh',
    padding: '20px',
    fontFamily: "'Press Start 2P', cursive",
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
  },
  title: {
    fontSize: '24px',
    marginBottom: '20px',
  },
  form: {
    display: 'flex',
    flexDirection: 'column',
    gap: '10px',
    width: '300px',
    marginBottom: '30px',
  },
  input: {
    padding: '10px',
    borderRadius: '5px',
    border: '1px solid #7FC6A4',
    fontSize: '14px',
  },
  button: {
    backgroundColor: '#386C0B',
    color: '#FFF',
    padding: '10px',
    borderRadius: '5px',
    cursor: 'pointer',
  },
  subTitle: {
    fontSize: '18px',
    marginTop: '20px',
  },
  playerList: {
    display: 'flex',
    flexWrap: 'wrap',
    gap: '20px',
    justifyContent: 'center',
  },
  playerCard: {
    backgroundColor: '#7FC6A4',
    padding: '15px',
    borderRadius: '10px',
    width: '250px',
    textAlign: 'center',
    boxShadow: '2px 2px 5px #386C0B',
  },
  buttonGroup: {
    display: 'flex',
    justifyContent: 'space-between',
    marginTop: '10px',
  },
  editButton: {
    backgroundColor: '#7FC6A4',
    padding: '5px 10px',
  },
  removeButton: {
    backgroundColor: '#FF4D4D',
    padding: '5px 10px',
  },
  backButton: {
    marginTop: '30px',
    backgroundColor: '#5D737E',
    padding: '10px 20px',
  },
};

export default PlayersManagement;
